  let setUploadedImage=async t=>{
    e.value=t;
    if(!t){
      gradcamOverlay.value=null;
      isLeaf.value=true;
      errorMessage.value=null;
      diagnosisId.value=null;
      return;
    }
    isAnalyzing.value=true;
    isLeaf.value=true;
    errorMessage.value=null;
    gradcamOverlay.value=null;
    try{
      const res=await fetch(t);
      const blob=await res.blob();
      const formData=new FormData();
      formData.append("file",blob,"image.jpg");
      formData.append("language","en");
      const apiBase=window.VITE_API_BASE_URL||"https://ai-plant-backend-92602424907.asia-south1.run.app";
      const apiRes=await fetch(`${apiBase}/api/v1/diagnose`,{method:"POST",body:formData});
      if(!apiRes.ok)throw new Error(`Server returned error status: ${apiRes.status}`);
      const data=await apiRes.json();
      if(!data.is_leaf){
        isLeaf.value=false;
        errorMessage.value=data.error_message||"Uploaded image is not a plant leaf.";
        isAnalyzing.value=false;
        return;
      }
      diagnosisId.value=data.diagnosis_id;
      gradcamOverlay.value=data.gradcam_overlay;
      
      const topPreds=data.top_predictions.map((p,idx)=>({
        label:p.disease_name_en,
        confidence:Math.round(p.confidence*100),
        color:idx===0?`#1D9E75`:`#9FE1CB`
      }));
      predictions.value=topPreds;
      
      const top=data.top_predictions[0];
      let crop="Plant",disease=top.disease_name_en;
      if(top.disease_raw && top.disease_raw.includes("___")){
        const parts=top.disease_raw.split("___");
        crop=parts[0].replace(/_/g," ");
        disease=parts[1].replace(/_/g," ");
      }
      
      const scMap={
        "Tomato":"Solanum lycopersicum - Tomato",
        "Potato":"Solanum tuberosum - Potato",
        "Pepper, bell":"Capsicum annuum - Bell Pepper",
        "Grape":"Vitis vinifera - Grape",
        "Corn":"Zea mays - Corn",
        "Apple":"Malus domestica - Apple"
      };
      const scientificName=scMap[crop]||`${crop}`;
      
      currentDisease.value={
        name:disease,
        scientificName:scientificName,
        severity:top.confidence>0.8?`Severe`:`Moderate`,
        about:`A pathogen-related condition (${disease}) has been identified on the leaf surface of this ${crop} plant, classified with ${Math.round(top.confidence*100)}% model confidence.`,
        tags:[`Pathogen: ${disease}`,`Host: ${crop}`,`Model Confidence: ${Math.round(top.confidence*100)}%`]
      };
      
      const regions=data.explainable_regions?[
        {title:`PRIMARY REGION`,feature:data.explainable_regions.primary_region||`Leaf surface`,activation:data.explainable_regions.activation_level||`High`,color:`#993C1D`},
        {title:`FEATURE DETECTED`,feature:data.explainable_regions.feature_detected||`Symptom pattern`,activation:`Medium`,color:`#BA7517`},
        {title:`TEXTURE`,feature:`Border halo`,activation:`Low`,color:`#3B6D11`}
      ]:[];
      xaiAnalysis.value={
        description:data.explainable_regions?`The model highlighted the primary diagnostic regions below. High activation (red) indicates crucial features.`:`No explainable regions returned from the model.`,
        regions:regions
      };
    }catch(err){
      console.error(err);
      errorMessage.value=err.message||"Failed to connect to backend.";
      isLeaf.value=false;
    }finally{
      isAnalyzing.value=false;
    }
  };
  
  return {
    uploadedImage:e,
    isAnalyzing,
    gradcamOverlay,
    isLeaf,
    errorMessage,
    diagnosisId,
    currentDisease,
    predictions,
    xaiAnalysis,
    setUploadedImage
  };
